; 愚者の倉庫

name = 愚者の倉庫３
insideName = Floor 3
level = 23
bgm = trick
shadow = dark
sky = black
roof = stone
blank = rock
antiWarp = true

; 各パーツ
━ = stone
　 = marble
☆ = soilr
❑ = cube
／ = door
⧻ = fence
☖ = arch
☗ = gate
︻ = panel

; 移動ポイント
(A) = map:愚者の倉庫２, x:10, y:0, way:n, symbol:exit, ask:Go to the previous floor?
(B) = map:愚者の倉庫４, x:0, y:3, way:e, symbol:exit, ask:Go to the next floor?

; 宝箱
box[1] = 罠はない,パワーガードの魔法書_u,元気のタンバリン_u,ポラリスの宝珠

[map]
