[correct]

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

switchFence(1, 7, "w", events.has(1) ? "close" : "open");
switchFence(8, 6, "e", events.has(1) ? "close" : "open");
pos[10][3].event = 3;

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] party.lastIsPush

[eventoff cond='game.map.getFloorInfo(1, 2).type != "movable"']
[eventoff cond='game.map.getFloorInfo(2, 2).type != "movable"']
[eventoff cond='game.map.getFloorInfo(3, 2).type != "movable"']
[eventoff cond='game.map.getFloorInfo(1, 1).type != "movable"']
[eventoff cond='game.map.getFloorInfo(2, 1).type != "movable"']
[eventoff cond='game.map.getFloorInfo(3, 1).type != "movable"']
[eventoff cond='game.map.getFloorInfo(1, 0).type != "movable"']
[eventoff cond='game.map.getFloorInfo(2, 0).type != "movable"']
[eventoff cond='game.map.getFloorInfo(3, 0).type != "movable"']
[eventoff cond='game.map.getFloorInfo(4, 0).type != "movable"']
@delevent
@wait time=1000
@se f=fence
@switchfence x=1 y=7 way=w mode=open
@switchfence x=8 y=6 way=e mode=open
@notice text="I heard a door open somewhere!"
@eval exp='o.倉庫整理のお仕事.flag = 2'

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="Finally, think carefully about the order in which you place the stones."

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] isDemoVersion

@notice text="<y>Thank you for your hard work. Please continue playing in the full version.<r>(You can save in free mode.)"
@walk move=n

[eventoff]
;-------------------------------------------------------------------------------
*reset_floor

[if exp='! game.map.events.has(1)']
	@call storage="anime.ks" target=*failed_to_reset
	[eventoff]
[endif]

@se f=dragstone
@eval exp='game.map.reset()'
@wait time=800
@warp x=8 y=7 way=s
@notice text="All the stones on the floor have returned to their original positions. You were warped back to near the entrance!"

[eventoff]
;-------------------------------------------------------------------------------
